CREATE OR REPLACE FUNCTION fpb_gos_payment_share (as_memno char) RETURNS timestamp(0) AS $body$
DECLARE

  ldt_lastday timestamp(0);

BEGIN
  /*
    วันที่ชำระล่าสุด จากรายการเคลื่อนไหว
  */
  select max(operate_date)
  into STRICT ldt_lastday
  from (
    SELECT ld.operate_date
      , sum( ld.share_value*lu.sign_flag) as sum_p
    from sc_mem_m_share_holding_detail ld
     , sc_mem_m_ucf_share_item_type lu
    where ld.membership_no = as_memno  -- 028961
    and ld.item_type = lu.item_type
    group by ld.operate_date
    order by ld.operate_date
  ) alias2
  where sum_p > 0;
  return ldt_lastday;
exception when others then CALL spa_dberror('fpb_gos_payment_share');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
